import React, { useState } from 'react';
import { useContent } from '../context/ContentContext';
import { generateContentDescription } from '../services/geminiService';
import { Trash2, Plus, Sparkles, LogOut, BarChart as ChartIcon, FileText, Layout as LayoutIcon } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';

// Mock Analytics Data
const ANALYTICS_DATA = [
  { name: 'Mon', visitors: 120 },
  { name: 'Tue', visitors: 150 },
  { name: 'Wed', visitors: 200 },
  { name: 'Thu', visitors: 180 },
  { name: 'Fri', visitors: 250 },
  { name: 'Sat', visitors: 190 },
  { name: 'Sun', visitors: 140 },
];

const Admin: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [password, setPassword] = useState('');
  const [activeTab, setActiveTab] = useState<'projects' | 'blog' | 'analytics'>('analytics');

  // Content State
  const { projects, blogs, addProject, addBlog, deleteProject, deleteBlog } = useContent();

  // Form State
  const [newItemTitle, setNewItemTitle] = useState('');
  const [newItemCategory, setNewItemCategory] = useState('');
  const [newItemImage, setNewItemImage] = useState('');
  const [newItemDescription, setNewItemDescription] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'admin') {
      setIsAuthenticated(true);
    } else {
      alert('Incorrect password. Try "admin"');
    }
  };

  const handleGenerateAI = async (type: 'project' | 'blog') => {
    if (!newItemTitle) {
      alert("Please enter a title first so AI knows what to write about.");
      return;
    }
    setIsGenerating(true);
    try {
      const text = await generateContentDescription(newItemTitle, type);
      setNewItemDescription(text);
    } catch (e) {
      alert("Failed to generate content. Check console/API key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAddProject = (e: React.FormEvent) => {
    e.preventDefault();
    addProject({
      id: Date.now().toString(),
      title: newItemTitle,
      category: newItemCategory || 'Uncategorized',
      location: 'New Location',
      year: new Date().getFullYear().toString(),
      image: newItemImage || `https://picsum.photos/1200/800?random=${Date.now()}`,
      description: newItemDescription,
      isFeatured: false,
    });
    resetForm();
  };

  const handleAddBlog = (e: React.FormEvent) => {
    e.preventDefault();
    addBlog({
      id: Date.now().toString(),
      title: newItemTitle,
      date: new Date().toLocaleDateString(),
      author: 'Admin',
      image: newItemImage || `https://picsum.photos/800/600?random=${Date.now()}`,
      excerpt: newItemDescription.substring(0, 100) + '...',
      content: newItemDescription,
    });
    resetForm();
  };

  const resetForm = () => {
    setNewItemTitle('');
    setNewItemCategory('');
    setNewItemImage('');
    setNewItemDescription('');
  };

  if (!isAuthenticated) {
    return (
      <div className="flex items-center justify-center min-h-[60vh] bg-gray-50">
        <div className="bg-white p-8 shadow-xl max-w-sm w-full">
          <h2 className="text-2xl font-serif mb-6 text-center">Staff Access</h2>
          <form onSubmit={handleLogin} className="space-y-4">
            <input 
              type="password" 
              placeholder="Enter Password (admin)" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full border p-3 outline-none focus:border-black"
            />
            <button className="w-full bg-black text-white p-3 font-bold uppercase hover:bg-gray-800 transition">
              Login
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 flex">
      {/* Sidebar */}
      <aside className="w-64 bg-white border-r border-gray-200 hidden md:block">
        <div className="p-6 border-b border-gray-200">
          <h2 className="text-xl font-serif font-bold">Anvitam Admin</h2>
        </div>
        <nav className="p-4 space-y-2">
           <button 
            onClick={() => setActiveTab('analytics')}
            className={`w-full text-left p-3 flex items-center space-x-3 rounded-lg transition-colors ${activeTab === 'analytics' ? 'bg-black text-white' : 'hover:bg-gray-100 text-gray-600'}`}
          >
            <ChartIcon size={18} />
            <span>Dashboard</span>
          </button>
          <button 
            onClick={() => setActiveTab('projects')}
            className={`w-full text-left p-3 flex items-center space-x-3 rounded-lg transition-colors ${activeTab === 'projects' ? 'bg-black text-white' : 'hover:bg-gray-100 text-gray-600'}`}
          >
            <LayoutIcon size={18} />
            <span>Projects</span>
          </button>
          <button 
            onClick={() => setActiveTab('blog')}
            className={`w-full text-left p-3 flex items-center space-x-3 rounded-lg transition-colors ${activeTab === 'blog' ? 'bg-black text-white' : 'hover:bg-gray-100 text-gray-600'}`}
          >
            <FileText size={18} />
            <span>Journal</span>
          </button>
          <div className="pt-8 mt-8 border-t border-gray-100">
            <button onClick={() => setIsAuthenticated(false)} className="w-full text-left p-3 flex items-center space-x-3 text-red-500 hover:bg-red-50 rounded-lg">
              <LogOut size={18} />
              <span>Logout</span>
            </button>
          </div>
        </nav>
      </aside>

      {/* Main Content */}
      <div className="flex-1 p-8 overflow-y-auto">

        {/* Analytics View */}
        {activeTab === 'analytics' && (
          <div className="space-y-6 animate-fade-in">
            <h2 className="text-3xl font-serif">Dashboard Overview</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 shadow-sm border border-gray-100">
                <h3 className="text-gray-500 text-xs font-bold uppercase">Total Projects</h3>
                <p className="text-4xl font-serif mt-2">{projects.length}</p>
              </div>
              <div className="bg-white p-6 shadow-sm border border-gray-100">
                <h3 className="text-gray-500 text-xs font-bold uppercase">Blog Posts</h3>
                <p className="text-4xl font-serif mt-2">{blogs.length}</p>
              </div>
              <div className="bg-white p-6 shadow-sm border border-gray-100">
                <h3 className="text-gray-500 text-xs font-bold uppercase">Weekly Visitors</h3>
                <p className="text-4xl font-serif mt-2">1,230</p>
              </div>
            </div>

            <div className="bg-white p-6 shadow-sm border border-gray-100 h-96">
              <h3 className="text-lg font-bold mb-6">Visitor Traffic</h3>
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={ANALYTICS_DATA}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} />
                  <XAxis dataKey="name" tickLine={false} axisLine={false} />
                  <YAxis tickLine={false} axisLine={false} />
                  <Tooltip cursor={{fill: '#f4f4f4'}} contentStyle={{border: 'none', borderRadius: '4px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} />
                  <Bar dataKey="visitors" fill="#1a1a1a" radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>
        )}

        {/* Project Manager View */}
        {activeTab === 'projects' && (
          <div className="space-y-8 animate-fade-in">
             <div className="flex justify-between items-center">
              <h2 className="text-3xl font-serif">Manage Projects</h2>
            </div>

            {/* Add Project Form */}
            <div className="bg-white p-6 shadow-sm border border-gray-100">
              <h3 className="text-lg font-bold mb-4 flex items-center"><Plus size={18} className="mr-2"/> Add New Project</h3>
              <form onSubmit={handleAddProject} className="grid grid-cols-1 gap-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <input 
                    type="text" 
                    placeholder="Project Name" 
                    className="border p-3 outline-none focus:border-black"
                    value={newItemTitle}
                    onChange={(e) => setNewItemTitle(e.target.value)}
                    required
                  />
                  <input 
                    type="text" 
                    placeholder="Category (e.g. Residential)" 
                    className="border p-3 outline-none focus:border-black"
                    value={newItemCategory}
                    onChange={(e) => setNewItemCategory(e.target.value)}
                    required
                  />
                </div>
                <input 
                  type="text" 
                  placeholder="Image URL (e.g. https://...)" 
                  className="border p-3 outline-none focus:border-black"
                  value={newItemImage}
                  onChange={(e) => setNewItemImage(e.target.value)}
                />
                <div className="relative">
                  <textarea 
                    placeholder="Description" 
                    rows={3}
                    className="w-full border p-3 outline-none focus:border-black pr-32"
                    value={newItemDescription}
                    onChange={(e) => setNewItemDescription(e.target.value)}
                    required
                  />
                  <button 
                    type="button"
                    onClick={() => handleGenerateAI('project')}
                    disabled={isGenerating}
                    className="absolute top-2 right-2 flex items-center space-x-1 bg-blue-50 text-blue-600 text-xs px-2 py-1 rounded hover:bg-blue-100 transition"
                  >
                    <Sparkles size={12} />
                    <span>{isGenerating ? 'Thinking...' : 'AI Generate'}</span>
                  </button>
                </div>
                <button type="submit" className="bg-black text-white py-3 uppercase font-bold tracking-widest hover:bg-gray-800">
                  Add Project
                </button>
              </form>
            </div>

            {/* List */}
            <div className="bg-white shadow-sm border border-gray-100">
              {projects.map(p => (
                <div key={p.id} className="flex items-center justify-between p-4 border-b last:border-0 hover:bg-gray-50">
                  <div className="flex items-center space-x-4">
                    <img src={p.image} alt={p.title} className="w-16 h-16 object-cover bg-gray-200" />
                    <div>
                      <h4 className="font-bold">{p.title}</h4>
                      <p className="text-sm text-gray-500">{p.category}</p>
                    </div>
                  </div>
                  <button onClick={() => deleteProject(p.id)} className="text-red-400 hover:text-red-600 p-2">
                    <Trash2 size={20} />
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Blog Manager View */}
        {activeTab === 'blog' && (
          <div className="space-y-8 animate-fade-in">
             <div className="flex justify-between items-center">
              <h2 className="text-3xl font-serif">Manage Journal</h2>
            </div>

            {/* Add Blog Form */}
             <div className="bg-white p-6 shadow-sm border border-gray-100">
              <h3 className="text-lg font-bold mb-4 flex items-center"><Plus size={18} className="mr-2"/> Add New Post</h3>
              <form onSubmit={handleAddBlog} className="grid grid-cols-1 gap-4">
                <input 
                  type="text" 
                  placeholder="Post Title" 
                  className="border p-3 outline-none focus:border-black"
                  value={newItemTitle}
                  onChange={(e) => setNewItemTitle(e.target.value)}
                  required
                />
                 <input 
                  type="text" 
                  placeholder="Image URL" 
                  className="border p-3 outline-none focus:border-black"
                  value={newItemImage}
                  onChange={(e) => setNewItemImage(e.target.value)}
                />
                <div className="relative">
                  <textarea 
                    placeholder="Content / Excerpt" 
                    rows={5}
                    className="w-full border p-3 outline-none focus:border-black pr-32"
                    value={newItemDescription}
                    onChange={(e) => setNewItemDescription(e.target.value)}
                    required
                  />
                   <button 
                    type="button"
                    onClick={() => handleGenerateAI('blog')}
                    disabled={isGenerating}
                    className="absolute top-2 right-2 flex items-center space-x-1 bg-purple-50 text-purple-600 text-xs px-2 py-1 rounded hover:bg-purple-100 transition"
                  >
                    <Sparkles size={12} />
                    <span>{isGenerating ? 'Writing...' : 'AI Draft'}</span>
                  </button>
                </div>
                <button type="submit" className="bg-black text-white py-3 uppercase font-bold tracking-widest hover:bg-gray-800">
                  Publish Post
                </button>
              </form>
            </div>

            {/* List */}
            <div className="bg-white shadow-sm border border-gray-100">
              {blogs.map(b => (
                <div key={b.id} className="flex items-center justify-between p-4 border-b last:border-0 hover:bg-gray-50">
                  <div className="flex items-center space-x-4">
                    <img src={b.image} alt={b.title} className="w-16 h-16 object-cover bg-gray-200" />
                    <div>
                      <h4 className="font-bold">{b.title}</h4>
                      <p className="text-sm text-gray-500">{b.date} by {b.author}</p>
                    </div>
                  </div>
                   <button onClick={() => deleteBlog(b.id)} className="text-red-400 hover:text-red-600 p-2">
                    <Trash2 size={20} />
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

export default Admin;

