import React, { createContext, useContext, useState, ReactNode } from 'react';
import { Project, BlogPost, Service, DigitalProduct } from '../types';
import { INITIAL_PROJECTS, INITIAL_BLOGS, SERVICES, DIGITAL_PRODUCTS } from '../constants';

interface ContentContextType {
  projects: Project[];
  blogs: BlogPost[];
  services: Service[];
  digitalProducts: DigitalProduct[];
  addProject: (project: Project) => void;
  addBlog: (blog: BlogPost) => void;
  addService: (service: Service) => void;
  addDigitalProduct: (product: DigitalProduct) => void;
  deleteProject: (id: string) => void;
  deleteBlog: (id: string) => void;
  deleteService: (id: string) => void;
  deleteDigitalProduct: (id: string) => void;
}

const ContentContext = createContext<ContentContextType | undefined>(undefined);

export const ContentProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [projects, setProjects] = useState<Project[]>(INITIAL_PROJECTS);
  const [blogs, setBlogs] = useState<BlogPost[]>(INITIAL_BLOGS);
  const [services, setServices] = useState<Service[]>(SERVICES);
  const [digitalProducts, setDigitalProducts] = useState<DigitalProduct[]>(DIGITAL_PRODUCTS);

  const addProject = (project: Project) => {
    setProjects((prev) => [project, ...prev]);
  };

  const addBlog = (blog: BlogPost) => {
    setBlogs((prev) => [blog, ...prev]);
  };

  const addService = (service: Service) => {
    setServices((prev) => [...prev, service]);
  };

  const addDigitalProduct = (product: DigitalProduct) => {
    setDigitalProducts((prev) => [product, ...prev]);
  };

  const deleteProject = (id: string) => {
    setProjects((prev) => prev.filter(p => p.id !== id));
  }

  const deleteBlog = (id: string) => {
    setBlogs((prev) => prev.filter(b => b.id !== id));
  }

  const deleteService = (id: string) => {
    setServices((prev) => prev.filter(s => s.id !== id));
  }

  const deleteDigitalProduct = (id: string) => {
    setDigitalProducts((prev) => prev.filter(p => p.id !== id));
  }

  return (
    <ContentContext.Provider value={{ 
      projects, 
      blogs, 
      services, 
      digitalProducts, 
      addProject, 
      addBlog, 
      addService, 
      addDigitalProduct, 
      deleteProject, 
      deleteBlog, 
      deleteService, 
      deleteDigitalProduct 
    }}>
      {children}
    </ContentContext.Provider>
  );
};

export const useContent = () => {
  const context = useContext(ContentContext);
  if (context === undefined) {
    throw new Error('useContent must be used within a ContentProvider');
  }
  return context;
};

